#include <bits/stdc++.h>
using namespace std;
long long dp[1001];
bool b[1001];
void prime(int n){
	for(int i=2;i<=n;i++){
		if(!b[i])
			for(int j=i*2;j<=n;j+=i)b[j]=true;
	}
}
int main(){
    int n;
	cin>>n;
	prime(n);
	dp[0]=1;
	for(int i=2;i<=n;i++){
		if(!b[i]){
			for(int j=i;j<=n;j++)dp[j]+=dp[j-i];
		}
	}
	cout<<dp[n];
    return 0;
}
